const fmt = (n) => "$" + Math.round(n).toLocaleString();
const S = { heading: "'Playfair Display', Georgia, serif", body: "'DM Sans', sans-serif", navy: "#0A2342", gold: "#C4A44B", gray: "#6B7C8F", lightBg: "#FAFAF7", darkBg: "#0A2342" };

function PageWrapper({ children, bg = "#fff" }) {
  return <div style={{ minHeight: "calc(100vh - 72px)", background: bg, padding: "0 0 60px" }}>{children}</div>;
}

function SectionHeader({ tag, title, desc, light = false }) {
  return (
    <div style={{ textAlign: "center", marginBottom: 48, padding: "48px 24px 0" }}>
      <span style={{ fontSize: 11, color: S.gold, letterSpacing: 3, textTransform: "uppercase", fontFamily: S.body, fontWeight: 600 }}>{tag}</span>
      <h2 style={{ fontFamily: S.heading, fontSize: "clamp(26px, 4vw, 40px)", color: light ? "#fff" : S.navy, margin: "10px 0 0", fontWeight: 700 }}>{title}</h2>
      {desc && <p style={{ fontFamily: S.body, fontSize: 15, color: light ? "rgba(255,255,255,0.55)" : S.gray, marginTop: 14, maxWidth: 600, marginLeft: "auto", marginRight: "auto", lineHeight: 1.65 }}>{desc}</p>}
    </div>
  );
}

function Container({ children, style = {} }) {
  return <div style={{ maxWidth: 1100, margin: "0 auto", padding: "0 24px", ...style }}>{children}</div>;
}

function Btn({ children, onClick, primary = false, style = {} }) {
  const [hov, setHov] = useState(false);
  return (
    <button onClick={onClick} onMouseOver={() => setHov(true)} onMouseOut={() => setHov(false)}
      style={{ padding: "14px 32px", borderRadius: 6, fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: S.body, letterSpacing: 1.2, textTransform: "uppercase", transition: "all 0.3s", border: primary ? "none" : `1px solid ${hov ? S.gold : "rgba(255,255,255,0.25)"}`, background: primary ? (hov ? "#D4B85B" : S.gold) : "transparent", color: primary ? S.navy : (hov ? S.gold : "#fff"), transform: hov ? "translateY(-2px)" : "none", boxShadow: primary && hov ? "0 4px 20px rgba(196,164,75,0.3)" : "none", ...style }}>
      {children}
    </button>
  );
}

